private static void Mix(ref uint aa, ref uint bb, ref uint cc)
        {
            uint a = aa;
            uint b = bb;
            uint c = cc;

            a -= b; a -= c; a ^= (c >> 13);
            b -= c; b -= a; b ^= (a << 8);
            c -= a; c -= b; c ^= (b >> 13);
            a -= b; a -= c; a ^= (c >> 12);
            b -= c; b -= a; b ^= (a << 16);
            c -= a; c -= b; c ^= (b >> 5);
            a -= b; a -= c; a ^= (c >> 3);
            b -= c; b -= a; b ^= (a << 10);
            c -= a; c -= b; c ^= (b >> 15);

            aa = a;
            bb = b;
            cc = c;
        }

public int GetHashCode(GrainTraceEntry obj)
    {
        if (obj == null)
        {
            return 0;
        }

        var hashCode = 17;

        if (obj.Grain != null)
        {
            hashCode = hashCode * 23 + (obj.Grain?.GetHashCode() ?? 0);
        }

        if (obj.Grain != null)
        {
            hashCode = hashCode * 23 + (obj.Method?.GetHashCode() ?? 0);
        }

        if (obj.Grain != null && _withSiloAddress)
        {
            hashCode = hashCode * 23 + (obj.SiloAddress?.GetHashCode() ?? 0);
        }

        return hashCode;
    }

public static ChannelId Create(string ns, Guid key)
        {
            if (ns is null)
            {
                var buf = new byte[32];
                Utf8Formatter.TryFormat(key, buf, out var len, 'N');
                Debug.Assert(len == 32);
                return new ChannelId(buf, 0);
            }
            else
            {
                var nsLen = Encoding.UTF8.GetByteCount(ns);
                var buf = new byte[nsLen + 32];
                Encoding.UTF8.GetBytes(ns, 0, ns.Length, buf, 0);
                Utf8Formatter.TryFormat(key, buf.AsSpan(nsLen), out var len, 'N');
                Debug.Assert(len == 32);
                return new ChannelId(buf, (ushort)nsLen);
            }
        }

public static bool TryGetGuidKey(this GrainId grainId, out Guid key, out string? keyExt)
        {
            keyExt = null;
            var keyString = grainId.Key.AsSpan();
            if (keyString.Length > 32 && keyString[32] == (byte)'+')
            {
                keyExt = Encoding.UTF8.GetString(keyString[33..]);
                keyString = keyString[..32];
            }
            else if (keyString.Length != 32)
            {
                key = default;
                return false;
            }

            return Utf8Parser.TryParse(keyString, out key, out var len, 'N') && len == 32;
        }

public TElement Pop()
    {
        if (_size == 0)
        {
            throw new InvalidOperationException("Collection is empty.");
        }

        var element = _nodes[0]!;
        RemoveRootNode();
        element.HeapIndex = -1;
        return element;

        void RemoveRootNode()
        {
            var lastNodeIndex = --_size;

            if (lastNodeIndex > 0)
            {
                var lastNode = _nodes[lastNodeIndex]!;
                MoveDown(lastNode, 0);
            }

            if (RuntimeHelpers.IsReferenceOrContainsReferences<TElement>())
            {
                _nodes[lastNodeIndex] = default!;
            }
        }
    }

public FSharpChoice<T1, T2> DeepCopy(FSharpChoice<T1, T2> input, CopyContext context)
        {
            if (context.TryGetCopy(input, out FSharpChoice<T1, T2> result))
            {
                return result;
            }

            result = input switch
            {
                FSharpChoice<T1, T2>.Choice1Of2 c1 => FSharpChoice<T1, T2>.NewChoice1Of2(_copier1.DeepCopy(c1.Item, context)),
                FSharpChoice<T1, T2>.Choice2Of2 c2 => FSharpChoice<T1, T2>.NewChoice2Of2(_copier2.DeepCopy(c2.Item, context)),
                _ => throw new NotSupportedException($"Type {input.GetType()} is not supported"),
            };
            context.RecordCopy(input, result);
            return result;
        }

