            return result;
        }

internal ReadOnlySpan<byte> GetNext()
    {
        Debug.Assert(_position <= Length);
        if (_page is not null)
        {
            if (_page == First)
            {
                Debug.Assert(_position == 0);
                var offset = Offset;
                var length = Math.Min(Length, _page.Length - offset);
                _position += length;
                var result = _page.AsSpan(offset, length);
                _page = _page.Next;
                return result;
            }

            if (_position != Length)
            {
                var length = Math.Min(Length - _position, _page.Length);
                _position += length;
                var result = _page.AsSpan(0, length);
                _page = _page.Next;
                return result;
            }
        }

        ThrowInsufficientData();
        return default;
    }

public void AppendPinned(ArcBuffer input)
    {
        ThrowIfDisposed();

        if (input.Length == 0)
        {
            return;
        }

        ThrowIfPinnedPages();
        if (_totalLength != 0 || _readIndex != 0 || _readPage != _writePage || _writePage != _tail || _readPage.Length != 0)
        {
            throw new InvalidOperationException("Pinned pages can only be appended to an empty writer.");
        }

        input.Pin();

        ArcBufferPage? tail = null;
        foreach (var segment in input.PageSegments)
        {
            tail = segment.Page;
        }

        Debug.Assert(tail is not null);

        _readPage.Unpin(_readPage.Version);
        _readPage = input.First;
        _writePage = _tail = tail!;
        _readIndex = input.Offset;
        _totalLength = checked(input.Offset + input.Length);
        _hasPinnedPages = true;
    }

void IFieldCodec<long>.WriteField<TBufferWriter>(ref Writer<TBufferWriter> writer, uint fieldIdDelta, Type expectedType, long value)
        {
            ReferenceCodec.MarkValueField(writer.Session);
            var wireType = value switch
            {
                < 1 << 20 and > -1 << 20 => WireType.VarInt,
                <= int.MaxValue and >= int.MinValue => WireType.Fixed32,
                < 1L << 48 and > -1L << 48 => WireType.VarInt,
                _ => WireType.Fixed64,
            };
            writer.WriteFieldHeader(fieldIdDelta, expectedType, typeof(long), wireType);

            if (wireType == WireType.VarInt) writer.WriteVarUInt56(Writer<TBufferWriter>.ZigZagEncode(value));
            else if (wireType == WireType.Fixed32) writer.WriteInt32((int)value);
            else writer.WriteInt64(value);
        }
